```plantuml
@startuml
interface Account {
    + applyMonthlyChange()
}

class CreditAccount {
    ...someAttribute
    + applyMonthlyInterest()
    + applyMonthlyChange()
    ...someOtherMethod()
}

class DebitAccount {
    ...someAttribute
    + applyMonthlyInterest()
    + deactivateIfUnderBalanced()
    + applyMonthlyChange()
    ...someOtherMethod()
}

class PayrollAccount {
    ...someAttribute
    + applyMonthlyChange()
    ...someMethod()
}

class Bank {
    accounts: [Account]
    + applyAllMonthlyChanges()
}

CreditAccount ..|> Account
DebitAccount ..|> Account
PayrollAccount ..|> Account

Bank --> Account : "accounts"

note right of Bank::applyAllMonthlyChanges()
  applyAllMonthlyChanges(){
    ...
    for every account a in accounts{
      a.applyMonthlyChange
    }
  }
end note

@enduml
